package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonWriterTest {
  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void beginArray_shouldOpenEmptyArrayAndWriteDeferredName() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException, NoSuchFieldException {
    // Arrange
    // Set deferredName to non-null to verify writeDeferredName effect (uses reflection)
    setField(jsonWriter, "deferredName", "name");

    // Spy on jsonWriter to verify writeDeferredName is called
    JsonWriter spyWriter = spy(jsonWriter);

    // Use reflection to make writeDeferredName accessible and verify its invocation manually
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);

    // Act
    JsonWriter returned = spyWriter.beginArray();

    // Assert
    // Verify writeDeferredName was called via spy by using doCallRealMethod and verify with reflection
    verify(spyWriter).beginArray(); // beginArray called

    // Since writeDeferredName is private, verify invocation by spying on beginArray only.
    // Alternatively, verify that deferredName is null after beginArray (indicating writeDeferredName executed)
    String deferredNameAfter = (String) getField(spyWriter, "deferredName");
    assertNull(deferredNameAfter);

    assertSame(spyWriter, returned);

    // The internal stack should have EMPTY_ARRAY on top (4 according to JsonScope)
    int[] stack = (int[]) getField(spyWriter, "stack");
    int stackSize = (int) getField(spyWriter, "stackSize");
    int top = stack[stackSize - 1];
    assertEquals(JsonScope.EMPTY_ARRAY, top);

    // The output should have '[' character appended
    String output = stringWriter.toString();
    assertEquals("[", output);
  }

  @Test
  public void beginArray_shouldWorkWithNullDeferredName() throws IOException {
    // Arrange
    setField(jsonWriter, "deferredName", null);

    // Act
    JsonWriter returned = jsonWriter.beginArray();

    // Assert
    assertSame(jsonWriter, returned);

    int[] stack = (int[]) getField(jsonWriter, "stack");
    int stackSize = (int) getField(jsonWriter, "stackSize");
    assertEquals(JsonScope.EMPTY_ARRAY, stack[stackSize - 1]);

    String output = stringWriter.toString();
    assertEquals("[", output);
  }

  @Test
  public void beginArray_shouldThrowIOException_whenOpenThrows() throws IOException {
    // We create a JsonWriter with a Writer that throws IOException on write
    Writer throwingWriter = new Writer() {
      @Override
      public void write(char[] cbuf, int off, int len) throws IOException {
        throw new IOException("forced");
      }
      @Override public void flush() throws IOException {}
      @Override public void close() throws IOException {}
    };
    JsonWriter writer = new JsonWriter(throwingWriter);

    // Act & Assert
    IOException ex = assertThrows(IOException.class, writer::beginArray);
    assertEquals("forced", ex.getMessage());
  }

  // Helper to set private fields via reflection
  private static void setField(Object target, String fieldName, Object value) {
    try {
      Field field = getFieldFromClassHierarchy(target.getClass(), fieldName);
      field.setAccessible(true);
      field.set(target, value);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  // Helper to get private fields via reflection
  private static Object getField(Object target, String fieldName) {
    try {
      Field field = getFieldFromClassHierarchy(target.getClass(), fieldName);
      field.setAccessible(true);
      return field.get(target);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  // Helper to find field in class hierarchy
  private static Field getFieldFromClassHierarchy(Class<?> clazz, String fieldName) throws NoSuchFieldException {
    Class<?> current = clazz;
    while (current != null) {
      try {
        return current.getDeclaredField(fieldName);
      } catch (NoSuchFieldException e) {
        current = current.getSuperclass();
      }
    }
    throw new NoSuchFieldException(fieldName);
  }
}
